import {cn} from '@/lib/utils';

type CanvasOverlayCorner =
  | 'top-left'
  | 'top-right'
  | 'bottom-left'
  | 'bottom-right';

const CORNER_CLASSES: Record<CanvasOverlayCorner, string> = {
  'top-left': 'top-3 left-4',
  'top-right': 'top-3 right-4',
  'bottom-left': 'bottom-3 left-4',
  'bottom-right': 'bottom-3 right-4',
};

/**
 * Full-canvas HUD container. Fills its positioned parent, is itself
 * `pointer-events-none`, and provides named corner slots for identity
 * labels, action buttons, and status chips.
 *
 * The container has no height constraint — each corner child is absolutely
 * positioned independently, so top-left identity and bottom-right controls
 * don't fight over a shared bar.
 *
 * @example
 * <div className="relative flex-1">
 *   {canvas content}
 *   <CanvasOverlay>
 *     <CanvasOverlaySlot corner="top-left">
 *       <CanvasOverlayLabel>hub</CanvasOverlayLabel>
 *       <CanvasOverlayMeta>8/8 · 2 local · 6 remote</CanvasOverlayMeta>
 *     </CanvasOverlaySlot>
 *     <CanvasOverlaySlot corner="bottom-right">
 *       <Button size="sm">Stop</Button>
 *     </CanvasOverlaySlot>
 *   </CanvasOverlay>
 * </div>
 */
function CanvasOverlay({className, ...props}: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="canvas-overlay"
      className={cn(
        'pointer-events-none absolute inset-0 z-overlay',
        className
      )}
      {...props}
    />
  );
}

/**
 * Positions interactive content in one of four canvas corners.
 * Sets `pointer-events-auto` so children receive clicks.
 */
function CanvasOverlaySlot({
  corner,
  className,
  ...props
}: React.ComponentProps<'div'> & {corner: CanvasOverlayCorner}) {
  return (
    <div
      data-slot="canvas-overlay-slot"
      data-corner={corner}
      className={cn(
        'pointer-events-auto absolute flex items-center gap-2',
        CORNER_CLASSES[corner],
        className
      )}
      {...props}
    />
  );
}

/** Primary canvas label — app name, view title, or breadcrumb leaf. */
function CanvasOverlayLabel({
  className,
  ...props
}: React.ComponentProps<'span'>) {
  return (
    <span
      data-slot="canvas-overlay-label"
      className={cn(
        'truncate text-[13px] font-label font-semibold text-foreground',
        className
      )}
      {...props}
    />
  );
}

/** Secondary metadata — counts, status summaries, region tags. */
function CanvasOverlayMeta({
  className,
  ...props
}: React.ComponentProps<'span'>) {
  return (
    <span
      data-slot="canvas-overlay-meta"
      className={cn(
        'shrink-0 font-mono text-[12px] text-muted-foreground',
        className
      )}
      {...props}
    />
  );
}

export {
  CanvasOverlay,
  CanvasOverlaySlot,
  CanvasOverlayLabel,
  CanvasOverlayMeta,
};
export type {CanvasOverlayCorner};
